SELECT status, COUNT(order_id) AS order_count
FROM energy_orders
GROUP BY status;

SELECT order_id
FROM energy_orders
WHERE order_type_id = (SELECT order_type_id FROM order_types WHERE order_type_name = 'Production' LIMIT 1);

SELECT SUM(kwh) AS total_kwh
FROM energy_orders
WHERE order_type_id = (SELECT order_type_id FROM order_types WHERE order_type_name = 'Production');

SELECT DISTINCT ot.order_type_name
FROM order_types ot
JOIN energy_orders eo ON eo.order_type_id = ot.order_type_id;

SELECT order_type_name, COUNT(*) AS order_count
FROM order_types
GROUP BY order_type_name;

SELECT order_date, start_time, end_time
FROM energy_orders
WHERE order_id = 0;

SELECT order_type_name
FROM order_types
WHERE order_type_id = 1;
